import type {
  ScaleBand,
  ScaleLinear,
  ScaleLogarithmic,
  ScaleSymLog,
  ScaleTime,
} from 'd3-scale';

/**
 * Convert a stacked chart to present relative values, which are scaled to 100% within each timeframe / timestamp, or show absolute values
 * @public
 */
export const valueRepresentationOptions = ['absolute', 'relative'] as const;

/**
 * @public
 */
export type ValueRepresentation = (typeof valueRepresentationOptions)[number];

/**
 * Defines which scale to apply to the axis
 * @public
 */
export const axisScaleTypeOptions = ['linear', 'log'] as const;

/**
 * @public
 */
export type AxisScaleType = (typeof axisScaleTypeOptions)[number];

/**
 * @internal
 */
export type NumericScales =
  | ScaleLinear<number, number>
  | ScaleLogarithmic<number, number>
  | ScaleSymLog<number, number>;

/**
 * @internal
 */
export type CategoricalScales = ScaleBand<string>;

/**
 * @internal
 */
export type DateScales = ScaleTime<number, number>;

/**
 * @internal
 */
export type AnyScale = NumericScales | CategoricalScales | DateScales;

/**
 * @internal
 */
export type AnyNumberScale = NumericScales | DateScales;
